<template>
    <div id="registerpage">
        <loadings :isLoading="settings.base.beforeLoad? 1: 0"></loadings>
        <div v-if="!settings.base.beforeLoad" >
            <NavBar :isActive="settings.base.belong" :isLogin="settings.base.isLogin"
                    :user="settings.base.userInfo"></NavBar>

            <div class="container mundb-standard-container">
                <div class="row justify-content-sm-center">
                    <div class="col-sm-12 col-md-8 col-lg-6">
                        <div class="text-center" style="margin-top:10vh;margin-bottom:20px;">
                            <h1 style="padding:20px;display:inline-block;">CAOJ</h1>
                            <p>CAOJ's yet another Online Judge</p>
                        </div>
                        <div class="card">
                            <div class="card-header">
                                <ul class="nav nav-tabs card-header-tabs nav-justified nav-tabs-material"
                                    id="accountTab"
                                    role="tablist">
                                    <li class="nav-item">
                                        <a class="nav-link" id="login-tab" href="loginpage.html" role="tab">{{$t('DEFAULT.OJ_MESSAGE_LOGIN')}}</a>
                                    </li>
                                    <li class="nav-item">
                                        <a class="nav-link active" id="register-tab" role="tab">{{$t('DEFAULT.OJ_MESSAGE_REGISTER')}}</a>
                                    </li>
                                    <div class="nav-tabs-indicator" id="nav-tabs-indicator" style="left: 50%;"></div>
                                </ul>
                            </div>
                            <div class="tab-content" id="accountTabContent">
                                <div class="tab-pane fade show active" id="register" role="tabpanel">
                                    <form class="needs-validation" id="register_form"
                                          @submit.prevent="postRegisterForm()">
                                        <div class="card-body">
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.registerForm.account != '', 'is-focused': settings.registerForm.currentFocus == 'account' && settings.registerForm.hasFocus }">
                                                <label for="account" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_ACCOUNT')}}</label>
                                                <input data-placement="left" data-toggle="tooltip"
                                                       v-bind:data-original-title="$t('WARN.OJ_MESSAGE_ENG_AND_NUM_ONLY')"
                                                       type="text" name="account" class="form-control" id="account"
                                                       required="" v-model="forms.registerForm.account"
                                                       autocomplete="off"
                                                       @focus="isFocus('account');checkAccount()"
                                                       @blur="isBlur();checkAccount()" @keyup="checkAccount">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.registerForm.errorMessage.account==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'account') || forms.registerForm.account.length > 0 ? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.account}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled':forms.registerForm.nick != '', 'is-focused': settings.registerForm.currentFocus == 'nick' && settings.registerForm.hasFocus }">
                                                <label for="nick" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_NICK')}}</label>
                                                <input data-placement="left" data-toggle="tooltip"
                                                       v-bind:data-original-title="$t('WARN.OJ_MESSAGE_CHN_ALSO')"
                                                       type="text" name="nick" class="form-control" id="nick"
                                                       autocomplete="off" required="" v-model="forms.registerForm.nick"
                                                       @focus="isFocus('nick');checkNick()" @blur="isBlur();checkNick()"
                                                       @keyup="checkNick()">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.registerForm.errorMessage.nick==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'nick') || forms.registerForm.nick.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.nick}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <div style="float: left;width: 70%" class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.registerForm.email != '', 'is-focused': settings.registerForm.currentFocus == 'email' && settings.registerForm.hasFocus }">
                                                <label for="email" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_EMAIL')}}</label>
                                                <input type="email" name="email" class="form-control" id="email"
                                                       required="" autocomplete="off" v-model="forms.registerForm.email"
                                                       @focus="isFocus('email');checkEmail()"
                                                       @blur="isBlur();checkEmail()" @keyup="checkEmail()">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.registerForm.errorMessage.email==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'email') || forms.registerForm.email.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.email}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <template v-if="settings.registerForm.isVerifyEmail == true">
                                                <button type="button" disabled="disabled" id="verifying"
                                                        style="margin-bottom: 0px;float: right;width: 30%;margin-top: 26.4px;white-space: pre-line;position: relative;"
                                                        class="btn btn-info" data-placement="left" data-toggle="tooltip"
                                                        v-bind:data-original-title="$t('WARN.OJ_MESSAGE_SENDING_EMAIL')">
                                                <span><i class="fa fa-cog fa-spin fa-3x fa-fw"
                                                         style="font-size: 20px"></i></span> verifying
                                                </button>
                                            </template>
                                            <template v-else-if="settings.registerForm.remainVerifyTime == 0">
                                                <button type="button" id="verify"
                                                        style="margin-bottom: 0px;float: right;width: 25%;margin-top: 28px;white-space: pre-line"
                                                        class="btn btn-info" @click="verifyEmail()"
                                                        data-placement="right"
                                                        data-toggle="tooltip"
                                                        v-bind:data-original-title="$t('WARN.OJ_MESSAGE_SEND_EMAIL')">
                                                    {{$t('DEFAULT.OJ_MESSAGE_VERIFY_EMAIL')}}
                                                </button>
                                            </template>
                                            <template v-else>
                                                <button type="button" disabled="disabled"
                                                        style="margin-bottom: 0px;float: right;width: 30%;margin-top: 15px;white-space: pre-line"
                                                        class="btn btn-info">
                                                    {{$t('WARN.OJ_MESSAGE_RESEND_EMAIL.LEFT')}}{{settings.registerForm.remainVerifyTime}}{{$t('WARN.OJ_MESSAGE_RESEND_EMAIL.RIGHT')}}
                                                </button>
                                            </template>
                                            <div style="clear: both;"></div>
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.registerForm.vcode != '', 'is-focused': settings.registerForm.currentFocus == 'vcode' && settings.registerForm.hasFocus }">
                                                <label for="vcode" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_VERIFICATION_CODE')}}</label>
                                                <input type="text" name="vcode" class="form-control" value="" id="vcode"
                                                       autocomplete="off" required="" v-model="forms.registerForm.vcode"
                                                       @focus="isFocus('vcode')" @blur="isBlur();checkVcode()"
                                                       @keyup="checkVcode()">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.registerForm.errorMessage.vcode==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'vcode') || forms.registerForm.vcode.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.vcode}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <div style="clear: both;"></div>
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.registerForm.password != '', 'is-focused': settings.registerForm.currentFocus == 'password' && settings.registerForm.hasFocus }">
                                                <label for="password" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_PASSWORD')}}</label>
                                                <input type="password" name="password" class="form-control"
                                                       id="password"
                                                       autocomplete="off" required=""
                                                       v-model="forms.registerForm.password"
                                                       @focus="isFocus('password');checkPassword()"
                                                       @blur="isBlur();checkPassword()" @keyup="checkPassword()">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.registerForm.errorMessage.password==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'password') || forms.registerForm.password.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.password}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <div class="form-group bmd-form-group "
                                                 v-bind:class="{ 'is-filled': forms.registerForm.repeatPassword != '', 'is-focused': settings.registerForm.currentFocus == 'repeat_password' && settings.registerForm.hasFocus }">
                                                <label for="rptpassword" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_REPEAT_PASSWORD')}}</label>
                                                <input type="password" name="rptpassword" class="form-control"
                                                       id="rptpassword" autocomplete="off" required=""
                                                       v-model="forms.registerForm.repeatPassword"
                                                       @focus="isFocus('repeat_password');"
                                                       @blur="isBlur();" @keyup="checkRepassword()">
                                                <span v-bind:style="{display: 'inline-block', float: 'right', color:result.registerForm.errorMessage.repeatPassword==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.registerForm.hasFocus && settings.registerForm.currentFocus == 'repeat_password') || forms.registerForm.repeatPassword.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.registerForm.errorMessage.repeatPassword}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <!--<input type="hidden" name="csrf" class="form-control" id="csrf"-->
                                            <!--autocomplete="off" required="" v-model="forms.registerForm.csrf">-->
                                        </div>
                                        <div class="card-footer text-right">
                                            <a href="javascript:void(0)">
                                                <button name="reset" type="button" class="btn btn-danger"
                                                        @click="resetInput">
                                                    {{$t('DEFAULT.OJ_MESSAGE_RESET')}}
                                                </button>
                                            </a>
                                            <button v-if="result.registerForm.isRegister == true" disabled="disabled"
                                                    name="submit" type="button" class="btn btn-secondary">
                                                <!--{{$t('DEFAULT.OJ_MESSAGE_REGISTER')}}-->
                                                <i class="fa fa-cog fa-spin fa-3x fa-fw" style="font-size: 18px"></i>
                                            </button>
                                            <button v-else name="submit" type="submit" class="btn btn-secondary">
                                                {{$t('DEFAULT.OJ_MESSAGE_REGISTER')}}
                                                <!--<i class="fa fa-cog fa-spin fa-3x fa-fw"></i>-->
                                            </button>
                                        </div>
                                    </form>
                                </div>
                            </div>
                            <div class="text-center card-bottom socialite-section"></div>
                        </div>
                    </div>
                </div>
            </div>
            <template v-if="result.registerForm.modelOpen == true">
                <div class="modal fade" id="register_error" tabindex="-1" role="dialog"
                     aria-labelledby="register_error_title" aria-hidden="true">
                    <div class="modal-dialog modal-dialog-centered" role="document">
                        <div class="modal-content">
                            <div class="modal-body">
                                <h3 v-if="result.registerForm.hasError == true" style="color: #ff3f4c">
                                    {{$t('WARN.OJ_MESSAGE_UNSUCCESSFULLY_REGISTER')}}
                                </h3>
                                <h3 v-else style="color: green">
                                    {{$t('WARN.OJ_MESSAGE_SUCCESSFULLY_REGISTER')}}
                                </h3>
                                <br>
                                <p>{{result.registerForm.registerInfo}}</p>
                            </div>
                            <div class="modal-footer">
                                <button v-if="result.registerForm.hasError == true" type="button"
                                        class="btn btn-secondary"
                                        data-dismiss="modal" @click="closeModel()">
                                    OK
                                </button>
                                <button v-else type="button" class="btn btn-secondary" data-dismiss="modal"
                                        @click="shiftToLogin()">
                                    OK
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </template>
            <footers></footers>
        </div>

    </div>
</template>

<!--</template>-->
<script>
    /* eslint no-useless-escape: "off"*/
    /* eslint vue/valid-template-root: "off"*/
    import NavBar from "@/components/navbar/navbar";
    import fun from '@/assets/js/OJFunction'
    import {hex_md5} from '@/assets/js/md5.js'
    import Footers from "../../components/footer/footer";
    import Loadings from "@/components/loading/loading";

    export default {
        components: {Footers, NavBar, Loadings},
        data() {
            return {
                settings: {//页面配置
                    base: {
                        belong: "account",
                        beforeLoad: true,
                        isLogin: false,
                        user: new Object(),
                    },
                    registerForm: {
                        //表单focus
                        currentFocus: "",
                        hasFocus: false,
                        //邮箱验证
                        remainVerifyTime: 0,
                        isVerifyEmail: false,
                    }
                },
                forms: {
                    registerForm: {
                        account: '',
                        nick: '',
                        email: '',
                        password: '',
                        vcode: '',
                        repeatPassword: '',
                        csrf: ''
                    }
                },
                result: {//表单及页面结果
                    registerForm: {
                        registerInfo: '',
                        isRegister: false,
                        hasError: false,
                        errorMessage: {
                            account: '　',
                            nick: '　',
                            email: '　',
                            password: '　',
                            repeat_password: '　',
                            vcode: '　',
                        },
                        modelOpen: false,
                    }
                },
            }
        },
        methods: {
            postRegisterForm: function () {
                this.result.registerForm.modelOpen = false;
                this.result.registerForm.registerInfo = "";
                this.result.registerForm.isRegister = true;
                this.forms.registerForm.password = hex_md5(this.forms.registerForm.password);
                this.forms.registerForm.repeatPassword = hex_md5(this.forms.registerForm.repeatPassword);
                var _this = this
                window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/register', fun.stringify(_this.forms.registerForm)).then(function (res) {
                    let data = res.data
                    _this.result.registerForm.isRegister = false;
                    _this.result.registerForm.modelOpen = true;
                    var error_type = data.OJ_ERROR_TYPE;
                    if (error_type != _this.GLOBAL.OJ_ERROR_NO_ERROR) _this.result.registerForm.hasError = true;
                    if (error_type == _this.GLOBAL.OJ_ERROR_NOT_ALLOW_REGISTER) {
                        _this.result.registerForm.registerInfo = _this.$t('WARN.OJ_MESSAGE_NOT_ALLOW_REGISTER');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_IP_BE_BANNED) {
                        _this.result.registerForm.registerInfo = _this.$t('WARN.OJ_MESSAGE_IP_BE_BANNED');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_CSRF_INVALID) {
                        _this.result.registerForm.registerInfo = _this.$t('WARN.OJ_MESSAGE_CSRF_INVALID');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_WRONG_VCODE) {
                        _this.forms.registerForm.vcode = "";
                        $("#vcode").focus();
                        _this.result.registerForm.errorMessage.vcode = _this.$t('WARN.OJ_MESSAGE_WRONG_VCODE');
                        document.getElementById('vcode').setCustomValidity(_this.$t('WARN.OJ_MESSAGE_WRONG_VCODE'));
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_EXISTENT_ACCOUNT) {
                        $("#account").focus();
                        _this.result.registerForm.errorMessage.account = _this.$t('WARN.OJ_MESSAGE_EXISTENT_ACCOUNT');
                        document.getElementById('account').setCustomValidity(_this.$t('WARN.OJ_MESSAGE_EXISTENT_ACCOUNT'));
                    } else {
                        _this.result.registerForm.registerInfo = _this.$t('WARN.OJ_MESSAGE_JUMP_LOGIN');
                    }
                    if (_this.result.registerForm.registerInfo.length > 0) {
                        setTimeout(function () {
                            $('#register_error').modal({
                                backdrop: 'static'
                            })
                        }, 100)
                    }
                    if (_this.result.registerForm.hasError == false) {
                        setTimeout(function () {
                            window.location.href = "/loginpage.html";
                        }, 4000)
                    }
                }).catch(function (error) {
                    console.log(error)
                })
            },
            resetInput: function () {
                this.forms.registerForm.account = "";
                this.forms.registerForm.password = "";
                this.forms.registerForm.vcode = "";
                this.forms.registerForm.email = "";
                this.forms.registerForm.nick = "";
                this.forms.registerForm.repeatPassword = "";
            },
            isFocus: function (num) {
                this.settings.registerForm.currentFocus = num;
                this.settings.registerForm.hasFocus = true;
            },
            isBlur: function () {
                this.settings.registerForm.hasFocus = false;
            },
            checkAccount: function () {
                var strs = this.forms.registerForm.account;
                var data = document.getElementById('account');
                // alert(4);
                if (strs.length <= 3) {
                    this.result.registerForm.errorMessage.account = this.$t('WARN.OJ_MESSAGE_TOO_SHORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_SHORT'));
                } else if (strs.length >= 20) {
                    this.result.registerForm.errorMessage.account = this.$t('WARN.OJ_MESSAGE_TOO_LONG');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_LONG'));
                } else if (strs.replace(/[\W]/g, '') != strs) {
                    this.result.registerForm.errorMessage.account = this.$t('WARN.OJ_MESSAGE_CHN_NOT_SUPPORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_CHN_NOT_SUPPORT'));
                } else if (fun.checkSQL(strs) != "") {
                    var special = fun.checkSQL(strs);
                    this.result.registerForm.errorMessage.account = this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special;
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special);
                } else {
                    this.result.registerForm.errorMessage.account = this.$t('WARN.OJ_MESSAGE_ACCEPTABLE');
                    data.setCustomValidity("");
                }
            },
            checkNick: function () {
                var strs = this.forms.registerForm.nick;
                var data = document.getElementById('nick');
                if (strs.length <= 3) {
                    this.result.registerForm.errorMessage.nick = this.$t('WARN.OJ_MESSAGE_TOO_SHORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_SHORT'));
                } else if (strs.length >= 20) {
                    this.result.registerForm.errorMessage.nick = this.$t('WARN.OJ_MESSAGE_TOO_LONG');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_LONG'));
                } else if (fun.checkSQL(strs) != "") {
                    var special = fun.checkSQL(strs);
                    this.result.registerForm.errorMessage.nick = this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special;
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special);
                } else {
                    this.result.registerForm.errorMessage.nick = this.$t('WARN.OJ_MESSAGE_ACCEPTABLE');
                    data.setCustomValidity("");
                }
            },
            checkPassword: function () {
                var strs = this.forms.registerForm.password;
                var data = document.getElementById('password');
                this.checkRepassword();
                if (strs.length <= 5) {
                    this.result.registerForm.errorMessage.password = this.$t('WARN.OJ_MESSAGE_TOO_SHORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_SHORT'));
                } else if (strs.length >= 20) {
                    this.result.registerForm.errorMessage.password = this.$t('WARN.OJ_MESSAGE_TOO_LONG');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_LONG'));
                } else if (strs.replace(/[\W]/g, '') != strs) {
                    this.result.registerForm.errorMessage.password = this.$t('WARN.OJ_MESSAGE_CHN_NOT_SUPPORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_CHN_NOT_SUPPORT'));
                } else if (fun.checkSQL(strs) != "") {
                    var special = fun.checkSQL(strs);
                    this.result.registerForm.errorMessage.password = this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special;
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_EXIST_SENSITIVE_WORD') + special);
                } else {
                    this.result.registerForm.errorMessage.password = this.$t('WARN.OJ_MESSAGE_ACCEPTABLE');
                    data.setCustomValidity("");
                }
            },
            checkRepassword: function () {
                var strs = this.forms.registerForm.repeatPassword;
                var data = document.getElementById('rptpassword');
                if (strs.length <= 5) {
                    this.result.registerForm.errorMessage.repeatPassword = this.$t('WARN.OJ_MESSAGE_INCONSISTENT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_INCONSISTENT'));
                } else if (strs != this.forms.registerForm.password) {
                    this.result.registerForm.errorMessage.repeatPassword = this.$t('WARN.OJ_MESSAGE_INCONSISTENT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_INCONSISTENT'));
                } else {
                    this.result.registerForm.errorMessage.repeatPassword = this.$t('WARN.OJ_MESSAGE_ACCEPTABLE');
                    data.setCustomValidity("");
                }
            },
            checkEmail: function () {
                var strs = this.forms.registerForm.email;
                var data = document.getElementById('email');
                var reg = new RegExp("^[a-z0-9]+([._\\-]*[a-z0-9])*@([a-z0-9]+[-a-z0-9]*[a-z0-9]+.){1,63}[a-z0-9]+$");
                if (this.result.registerForm.errorMessage.email == this.$t('WARN.OJ_MESSAGE_CSRF_INVALID')) return;
                if (!reg.test(strs)) {
                    this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_EMAIL_ILLEGAL_FOEMAT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_EMAIL_ILLEGAL_FOEMAT'));
                } else if (strs.length <= 5) {
                    this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_TOO_SHORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_SHORT'));
                } else if (strs.length >= 30) {
                    this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_TOO_LONG');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_LONG'));
                } else {
                    this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_ACCEPTABLE');
                    data.setCustomValidity("");
                }
            },
            checkVcode: function () {
                var data = document.getElementById('vcode');
                this.result.registerForm.errorMessage.vcode = "";
                data.setCustomValidity("");
            },
            verifyEmail: function () {
                $('#verify').tooltip('hide');
                var data = document.getElementById('email');
                if (this.forms.registerForm.email.length == 0) {
                    $("#email").focus();
                    this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_TOO_SHORT');
                    data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_TOO_SHORT'));
                    return;
                }
                this.settings.registerForm.isVerifyEmail = true;
                this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/verify/email', {
                    email: this.forms.registerForm.email,
                    csrf: this.forms.registerForm.csrf
                }, {emulateJSON: true}).then(function (res) {
                    this.settings.registerForm.isVerifyEmail = false;
                    var error_type = res.body.OJ_ERROR_TYPE;
                    if (error_type == this.GLOBAL.OJ_ERROR_CSRF_INVALID) {
                        $("#email").focus();
                        this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_CSRF_INVALID');
                        data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_CSRF_INVALID'));
                    } else if (error_type == this.GLOBAL.OJ_ERROR_EXISTENT_EMAIL) {
                        $("#email").focus();
                        this.result.registerForm.errorMessage.email = this.$t('WARN.OJ_MESSAGE_EXISTENT_EMAIL');
                        data.setCustomValidity(this.$t('WARN.OJ_MESSAGE_EXISTENT_EMAIL'));
                    } else {
                        this.settings.registerForm.remainVerifyTime = 60;
                        this.updateEmailVerifyTime();
                    }
                }, function () {
                    console.log('请求失败处理');
                });
            },
            updateEmailVerifyTime: function () {
                if (this.settings.registerForm.remainVerifyTime > 0) {
                    this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/redis/getExpire', {
                        key: "register_vcode"
                    }, {emulateJSON: true}).then(function (res) {
                        this.settings.registerForm.remainVerifyTime = Number(res.body.OJ_EMAIL_INVALID_TIME);
                        var _this = this;
                        setTimeout(function () {
                            _this.updateEmailVerifyTime();
                        }, 500)
                    }, function () {
                        console.log('请求失败处理');
                    })
                }
            },
            closeModel: function () {
                var _this = this;
                setTimeout(function () {
                    _this.result.registerForm.modelOpen = false;
                    _this.result.registerForm.registerInfo = "";
                }, 300)
            },
            shiftToLogin: function () {
                window.location.href = "/loginpage.html";
            },
            identify: async function () {
                let data = await fun.idenfity();
                this.$i18n.locale = data.OJ_LANGUAGE_TYPE;
                if (data.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    this.settings.base.isLogin = true;
                    this.settings.base.user = data.OJ_USER_INFO;
                }
                return data;
            },
            searchRegisterSettings() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/register/settings', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            }
        },
        async created() {
            let res = await this.identify();
            if (res.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                window.history.go(-1);
                return;
            }
            var _this = this
            window.axios.all([_this.searchRegisterSettings()])
                .then(window.axios.spread((RegRes) => {
                    let RegData = RegRes.data;
                    _this.forms.registerForm.csrf = RegData.OJ_REG_CSRF;
                    _this.settings.registerForm.remainVerifyTime = Number(RegData.OJ_EMAIL_INVALID_TIME);
                    _this.settings.base.beforeLoad = false;
                    _this.updateEmailVerifyTime();
                }))
                .catch((error) => {
                    console.log(error)
                })
        }
    }
</script>
